SELECT m.id AS id, m.public_id::text AS publicKey, m.abbr AS abbr, m.name AS name, m.is_active AS isActive, m.created_by AS createdById, COALESCE( NULLIF(TRIM(CONCAT(COALESCE(uc.first_name, ''), ' ', COALESCE(uc.last_name, ''))), ''), uc.username, '' ) AS createdBy, TO_CHAR(m.created_at, 'DD-Mon-YYYY HH24:MI') AS created, m.modified_by AS modifiedById, COALESCE( NULLIF(TRIM(CONCAT(COALESCE(um.first_name, ''), ' ', COALESCE(um.last_name, ''))), ''), um.username, '' ) AS modifiedBy, TO_CHAR(m.modified_at, 'DD-Mon-YYYY HH24:MI') AS modified FROM modalities m LEFT JOIN users uc ON uc.id = m.created_by LEFT JOIN users um ON um.id = m.modified_by
ORDER BY m.id DESC
LIMIT #{rowsPerPage} OFFSET #{page}

SELECT CONCAT(COALESCE(NULLIF(abbr, ''), 'OT'), '_', name) FROM modalities WHERE is_active = 1 AND id IN
#{modalityId}
ORDER BY id ASC
